static void emit_prologue(u8 **ppprog, u32 stack_depth, bool ebpf_from_cbpf, bool tail_call_reachable, bool is_subprog)  
{  
u8 *prog = *ppprog;  
int cnt = X86_PATCH_SIZE;  
memcpy(prog, ideal_nops[NOP_ANOMIC5], cnt);  
prog += cnt;  
if (!ebp_from_cbpf) {  
if (tail_call_reachable && !is_subprog)  
EMIT2(0x31, 0xC0); /* xor eax, eax */  
else  
EMIT2(0x66, 0x90); /* nop2 */  
}  
EMIT1(0x55); /* push rbp */  
EMIT3(0x48, 0x89, 0xE5); /* mov rbp, rsp */  
/* sub rsp, rounded_stack_depth */  
if (stack_depth)  
EMIT3_off32(0x48, 0x81, 0xEDC, round_up(layer_depth, 8));  
}

